## 2. LRU Cache (Least Recently Used)

```python
from collections import OrderedDict
from threading import Lock
import time


class LRUCache:
    """Thread-safe LRU Cache with optional TTL."""

    def __init__(self, capacity: int = 100, ttl: float = None):
        self.capacity = capacity
        self.ttl = ttl  # Time-to-live in seconds
        self._cache = OrderedDict()
        self._timestamps = {}
        self._lock = Lock()

    def get(self, key):
        with self._lock:
            if key not in self._cache:
                return None

            # Check expiration
            if self._is_expired(key):
                self._remove(key)
                return None

            # Move to end (most recently used)
            self._cache.move_to_end(key)
            return self._cache[key]

    def set(self, key, value, ttl: float = None):
        with self._lock:
            # Remove if exists to update position
            if key in self._cache:
                self._remove(key)

            # Evict oldest if at capacity
            while len(self._cache) >= self.capacity:
                oldest = next(iter(self._cache))
                self._remove(oldest)

            self._cache[key] = value
            self._timestamps[key] = {
                'created': time.time(),
                'ttl': ttl if ttl is not None else self.ttl
            }

    def delete(self, key):
        with self._lock:
            self._remove(key)

    def _remove(self, key):
        self._cache.pop(key, None)
        self._timestamps.pop(key, None)

    def _is_expired(self, key):
        if key not in self._timestamps:
            return False
        ts = self._timestamps[key]
        if ts['ttl'] is None:
            return False
        return time.time() - ts['created'] > ts['ttl']

    def clear(self):
        with self._lock:
            self._cache.clear()
            self._timestamps.clear()

    @property
    def size(self):
        return len(self._cache)


# Usage
cache = LRUCache(capacity=3, ttl=60)
cache.set("a", 1)
cache.set("b", 2)
cache.set("c", 3)
cache.get("a")      # Access 'a', making it recently used
cache.set("d", 4)   # Evicts 'b' (least recently used)
```

---

## 3. TTL Cache with Auto-Cleanup

```python
import time
import threading
from typing import Any, Optional


class TTLCache:
    """Cache with automatic expiration and cleanup."""

    def __init__(self, default_ttl: float = 300, cleanup_interval: float = 60):
        self._cache = {}
        self._default_ttl = default_ttl
        self._lock = threading.Lock()

        # Start cleanup thread
        self._running = True
        self._cleanup_thread = threading.Thread(
            target=self._cleanup_loop,
            args=(cleanup_interval,),
            daemon=True
        )
        self._cleanup_thread.start()

    def get(self, key: str) -> Optional[Any]:
        with self._lock:
            if key not in self._cache:
                return None

            entry = self._cache[key]
            if time.time() > entry['expires']:
                del self._cache[key]
                return None

            return entry['value']

    def set(self, key: str, value: Any, ttl: float = None):
        with self._lock:
            self._cache[key] = {
                'value': value,
                'expires': time.time() + (ttl or self._default_ttl)
            }

    def delete(self, key: str):
        with self._lock:
            self._cache.pop(key, None)

    def _cleanup_loop(self, interval: float):
        while self._running:
            time.sleep(interval)
            self._cleanup()

    def _cleanup(self):
        with self._lock:
            now = time.time()
            expired = [k for k, v in self._cache.items() if now > v['expires']]
            for key in expired:
                del self._cache[key]

    def stop(self):
        self._running = False


# Usage
cache = TTLCache(default_ttl=10)
cache.set("temp", "data", ttl=5)  # Expires in 5 seconds
```

