## 4. Decorator Cache (Memoization)

```python
import functools
import time
from typing import Optional


def cached(ttl: Optional[float] = None, maxsize: int = 128):
    """Decorator to cache function results."""

    def decorator(func):
        cache = {}
        order = []

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            key = (args, tuple(sorted(kwargs.items())))

            # Check cache
            if key in cache:
                entry = cache[key]
                if ttl is None or time.time() - entry['time'] < ttl:
                    return entry['value']
                else:
                    del cache[key]
                    order.remove(key)

            # Compute result
            result = func(*args, **kwargs)

            # Store in cache
            cache[key] = {'value': result, 'time': time.time()}
            order.append(key)

            # Enforce maxsize
            while len(order) > maxsize:
                oldest = order.pop(0)
                cache.pop(oldest, None)

            return result

        wrapper.cache_clear = lambda: (cache.clear(), order.clear())
        wrapper.cache_info = lambda: {'size': len(cache), 'maxsize': maxsize}

        return wrapper
    return decorator


# Usage
@cached(ttl=60, maxsize=100)
def expensive_computation(x, y):
    time.sleep(1)  # Simulate expensive work
    return x + y

result = expensive_computation(1, 2)  # Takes 1 second
result = expensive_computation(1, 2)  # Instant (cached)
```

