## 5. Multi-Level Cache

```python
from abc import ABC, abstractmethod
from typing import Any, Optional, List


class CacheBackend(ABC):
    @abstractmethod
    def get(self, key: str) -> Optional[Any]: pass

    @abstractmethod
    def set(self, key: str, value: Any, ttl: float = None): pass

    @abstractmethod
    def delete(self, key: str): pass


class MemoryBackend(CacheBackend):
    def __init__(self):
        self._data = {}

    def get(self, key):
        return self._data.get(key)

    def set(self, key, value, ttl=None):
        self._data[key] = value

    def delete(self, key):
        self._data.pop(key, None)


class MultiLevelCache:
    """Cache with multiple layers (L1 -> L2 -> L3)."""

    def __init__(self, backends: List[CacheBackend]):
        self.backends = backends

    def get(self, key: str) -> Optional[Any]:
        for i, backend in enumerate(self.backends):
            value = backend.get(key)
            if value is not None:
                # Populate higher-level caches
                for j in range(i):
                    self.backends[j].set(key, value)
                return value
        return None

    def set(self, key: str, value: Any, ttl: float = None):
        for backend in self.backends:
            backend.set(key, value, ttl)

    def delete(self, key: str):
        for backend in self.backends:
            backend.delete(key)


# Usage
l1 = MemoryBackend()  # Fast, small
l2 = MemoryBackend()  # Slower, larger (could be Redis)

cache = MultiLevelCache([l1, l2])
cache.set("key", "value")
```

